237: // update the node associated with the connection, after receiving a packet from envoy, also adds the connection
238: // to the tracking map.
239: func (s *DiscoveryServer) initConnection(node *core.Node, con *Connection, identities []string) error {
240: 	// Setup the initial proxy metadata
241: 	proxy, err := s.initProxyMetadata(node)
242: 	if err != nil {
243: 		return err
244: 	}
245: 	// Check if proxy cluster has an alias configured, if yes use that as cluster ID for this proxy.
246: 	if alias, exists := s.ClusterAliases[proxy.Metadata.ClusterID]; exists {
247: 		proxy.Metadata.ClusterID = alias
248: 	}
249: 	// To ensure push context is monotonically increasing, setup LastPushContext before we addCon. This
250: 	// way only new push contexts will be registered for this proxy.
251: 	proxy.LastPushContext = s.globalPushContext()
252: 	// First request so initialize connection id and start tracking it.
253: 	con.SetID(connectionID(proxy.ID))
254: 	con.node = node
255: 	con.proxy = proxy
256: 	if proxy.IsZTunnel() && !features.EnableAmbient {
257: 		return fmt.Errorf("ztunnel requires PILOT_ENABLE_AMBIENT=true")
258: 	}
259: 
260: 	// Authorize xds clients
261: 	if err := s.authorize(con, identities); err != nil {
262: 		return err
263: 	}
264: 
265: 	// Register the connection. this allows pushes to be triggered for the proxy. Note: the timing of
266: 	// this and initializeProxy important. While registering for pushes *after* initialization is complete seems like
267: 	// a better choice, it introduces a race condition; If we complete initialization of a new push
268: 	// context between initializeProxy and addCon, we would not get any pushes triggered for the new
269: 	// push context, leading the proxy to have a stale state until the next full push.
270: 	s.addCon(con.ID(), con)
271: 	// Register that initialization is complete. This triggers to calls that it is safe to access the
272: 	// proxy
273: 	defer con.MarkInitialized()
274: 
275: 	// Complete full initialization of the proxy
276: 	if err := s.initializeProxy(con); err != nil {
277: 		s.closeConnection(con)
278: 		return err
279: 	}
280: 	return nil
281: }
