296: // initProxyMetadata initializes just the basic metadata of a proxy. This is decoupled from
297: // initProxyState such that we can perform authorization before attempting expensive computations to
298: // fully initialize the proxy.
299: func (s *DiscoveryServer) initProxyMetadata(node *core.Node) (*model.Proxy, error) {
300: 	meta, err := model.ParseMetadata(node.Metadata)
301: 	if err != nil {
302: 		return nil, status.New(codes.InvalidArgument, err.Error()).Err()
303: 	}
304: 	proxy, err := model.ParseServiceNodeWithMetadata(node.Id, meta)
305: 	if err != nil {
306: 		return nil, status.New(codes.InvalidArgument, err.Error()).Err()
307: 	}
308: 	// Update the config namespace associated with this proxy
309: 	proxy.ConfigNamespace = model.GetProxyConfigNamespace(proxy)
310: 	proxy.XdsNode = node
311: 	return proxy, nil
