314: // setTopologyLabels sets locality, cluster, network label
315: // must be called after `SetWorkloadLabels` and `SetServiceTargets`.
316: func setTopologyLabels(proxy *model.Proxy) {
317: 	// This is a bit un-intuitive, but pull the locality from Labels first. The service registries have the best access to
318: 	// locality information, as they can read from various sources (Node on Kubernetes, for example). They will take this
319: 	// information and add it to the labels. So while the proxy may not originally have these labels,
320: 	// it will by the time we get here (as a result of calling this after SetWorkloadLabels).
321: 	proxy.Locality = localityFromProxyLabels(proxy)
322: 	if proxy.Locality == nil {
323: 		// If there is no locality in the registry then use the one sent as part of the discovery request.
324: 		// This is not preferable as only the connected Pilot is aware of this proxies location, but it
325: 		// can still help provide some client-side Envoy context when load balancing based on location.
326: 		proxy.Locality = &core.Locality{
327: 			Region:  proxy.XdsNode.Locality.GetRegion(),
328: 			Zone:    proxy.XdsNode.Locality.GetZone(),
329: 			SubZone: proxy.XdsNode.Locality.GetSubZone(),
330: 		}
331: 	}
332: 	// add topology labels to proxy labels
333: 	proxy.Labels = labelutil.AugmentLabels(
334: 		proxy.Labels,
335: 		proxy.Metadata.ClusterID,
336: 		util.LocalityToString(proxy.Locality),
337: 		proxy.GetNodeName(),
338: 		proxy.Metadata.Network,
339: 	)
340: }
