342: func localityFromProxyLabels(proxy *model.Proxy) *core.Locality {
343: 	region, f1 := proxy.Labels[labelutil.LabelTopologyRegion]
344: 	zone, f2 := proxy.Labels[labelutil.LabelTopologyZone]
345: 	subzone, f3 := proxy.Labels[label.TopologySubzone.Name]
346: 	if !f1 && !f2 && !f3 {
347: 		// If no labels set, we didn't find the locality from the service registry. We do support a (mostly undocumented/internal)
348: 		// label to override the locality, so respect that here as well.
349: 		ls, f := proxy.Labels[model.LocalityLabel]
350: 		if f {
351: 			return util.ConvertLocality(ls)
352: 		}
353: 		return nil
354: 	}
355: 	return &core.Locality{
356: 		Region:  region,
357: 		Zone:    zone,
358: 		SubZone: subzone,
359: 	}
360: }
