{"content":"800: // It filters destinations present in VirtualService by using configNamespace, when the value is empty string, then filtering is disabled
801: func virtualServiceDestinationsFilteredBySourceNamespace(v *networking.VirtualService, configNamespace string) map[string]sets.Set[int] {
802: 	if v == nil {
803: 		return nil
804: 	}
805: 
806: 	out := make(map[string]sets.Set[int])
807: 
808: 	addDestination := func(host string, port *networking.PortSelector) {
809: 		// Use the value 0 as a sentinel indicating that one of the destinations
810: 		// in the Virtual Service does not specify a port for this host.
811: 		pn := 0
812: 		if port != nil {
813: 			pn = int(port.Number)
814: 		}
815: 		sets.InsertOrNew(out, host, pn)
816: 	}
817: 
818: 	for _, h := range v.Http {
819: 		if configNamespace != "" {
820: 			namespaceMatched := true
821: 			for _, m := range h.Match {
822: 				if m.SourceNamespace != "" {
823: 					if m.SourceNamespace == configNamespace {
824: 						namespaceMatched = true
825: 						break
826: 					}
827: 					namespaceMatched = false
828: 				}
829: 			}
830: 			if !namespaceMatched {
831: 				continue
832: 			}
833: 		}
834: 		for _, r := range h.Route {
835: 			if r.Destination != nil {
836: 				addDestination(r.Destination.Host, r.Destination.GetPort())
837: 			}
838: 		}
839: 		if h.Mirror != nil {
840: 			addDestination(h.Mirror.Host, h.Mirror.GetPort())
841: 		}
842: 		for _, m := range h.Mirrors {
843: 			if m.Destination != nil {
844: 				addDestination(m.Destination.Host, m.Destination.GetPort())
845: 			}
846: 		}
847: 	}
848: 	for _, t := range v.Tcp {
849: 		for _, r := range t.Route {
850: 			if r.Destination != nil {
851: 				addDestination(r.Destination.Host, r.Destination.GetPort())
852: 			}
853: 		}
854: 	}
855: 	for _, t := range v.Tls {
856: 		for _, r := range t.Route {
857: 			if r.Destination != nil {
858: 				addDestination(r.Destination.Host, r.Destination.GetPort())
859: 			}
860: 		}
861: 	}
862: 
863: 	return out
864: }
