961: // 2. RequestAuthentication.JwtRules.JwksUri
962: // 3. EnvoyFilters with explicitly annotated references
963: func (ps *PushContext) extraServicesForProxy(proxy *Proxy, patches *MergedEnvoyFilterWrapper) (sets.Set[NamespacedHostname], sets.String) {
964: 	hosts := sets.String{}
965: 	namespaceScoped := sets.New[NamespacedHostname]()
966: 	addService := func(s string) {
967: 		if ns, h, ok := strings.Cut(s, "/"); ok {
968: 			namespaceScoped.Insert(NamespacedHostname{
969: 				Hostname:  host.Name(h),
970: 				Namespace: ns,
971: 			})
972: 		} else {
973: 			hosts.Insert(s)
974: 		}
975: 	}
976: 	// add services from MeshConfig.ExtensionProviders
977: 	for _, prov := range ps.Mesh.ExtensionProviders {
978: 		switch p := prov.Provider.(type) {
979: 		case *meshconfig.MeshConfig_ExtensionProvider_EnvoyExtAuthzHttp:
980: 			addService(p.EnvoyExtAuthzHttp.Service)
981: 		case *meshconfig.MeshConfig_ExtensionProvider_EnvoyExtAuthzGrpc:
982: 			addService(p.EnvoyExtAuthzGrpc.Service)
983: 		case *meshconfig.MeshConfig_ExtensionProvider_Zipkin:
984: 			addService(p.Zipkin.Service)
985: 		case *meshconfig.MeshConfig_ExtensionProvider_Lightstep:
986: 			log.Warnf("Lightstep provider is deprecated, please use OpenTelemetry instead")
987: 		case *meshconfig.MeshConfig_ExtensionProvider_Datadog:
988: 			addService(p.Datadog.Service)
989: 		case *meshconfig.MeshConfig_ExtensionProvider_Skywalking:
990: 			addService(p.Skywalking.Service)
991: 		case *meshconfig.MeshConfig_ExtensionProvider_Opencensus:
992: 			log.Warnf("Opencensus provider is deprecated, please use OpenTelemetry instead")
993: 		case *meshconfig.MeshConfig_ExtensionProvider_Opentelemetry:
994: 			addService(p.Opentelemetry.Service)
995: 		case *meshconfig.MeshConfig_ExtensionProvider_EnvoyHttpAls:
996: 			addService(p.EnvoyHttpAls.Service)
997: 		case *meshconfig.MeshConfig_ExtensionProvider_EnvoyTcpAls:
998: 			addService(p.EnvoyTcpAls.Service)
999: 		case *meshconfig.MeshConfig_ExtensionProvider_EnvoyOtelAls:
1000: 			addService(p.EnvoyOtelAls.Service)
1001: 		case *meshconfig.MeshConfig_ExtensionProvider_Sds:
1002: 			addService(p.Sds.Service)
1003: 			// TODO: implement SDS provider
1004: 		case *meshconfig.MeshConfig_ExtensionProvider_EnvoyFileAccessLog: // No services
1005: 		case *meshconfig.MeshConfig_ExtensionProvider_Prometheus: // No services
1006: 		case *meshconfig.MeshConfig_ExtensionProvider_Stackdriver: // No services
1007: 		}
1008: 	}
1009: 	// add services from RequestAuthentication.JwtRules.JwksUri
1010: 	if features.JwksFetchMode != jwt.Istiod {
1011: 		forWorkload := PolicyMatcherForProxy(proxy)
1012: 		jwtPolicies := ps.AuthnPolicies.GetJwtPoliciesForWorkload(forWorkload)
1013: 		for _, cfg := range jwtPolicies {
1014: 			rules := cfg.Spec.(*v1beta1.RequestAuthentication).JwtRules
1015: 			for _, r := range rules {
1016: 				if uri := r.GetJwksUri(); len(uri) > 0 {
1017: 					jwksInfo, err := security.ParseJwksURI(uri)
1018: 					if err == nil {
1019: 						hosts.Insert(jwksInfo.Hostname.String())
1020: 					}
1021: 				}
1022: 			}
1023: 		}
1024: 	}
1025: 
1026: 	if patches != nil {
1027: 		namespaceScoped.Merge(patches.ReferencedNamespacedServices)
1028: 		hosts.Merge(patches.ReferencedServices)
1029: 	}
1030: 	return namespaceScoped, hosts
1031: }
